SELECT "Invoice" AS DocType, [Sales Invoice Line].Type, [Sales Invoice Header].No_, [Sales Invoice Header].[VAT Registration No_], [Sales Invoice Header].[Bill-to Name], [Sales Invoice Header].[Bill-to Country_Region Code], Item.[Country_Region of Origin Code], [Sales Invoice Header].[Ship-to Country_Region Code], Item.[Tariff No_], Val([item.Gross Weight])*Val([no_ of pairs]) AS PesoLordo, Val([no_ of pairs]) AS Unita, Item.Description, Val([Amount]) AS ImportoNetto, Val([Amount])+Val([inv_ discount amount])+Val([Line discount amount]) AS ImportoLordo, Item.[Trademark Code] AS Marchio, Vendor.Name AS Fornitore, [Sales Invoice Header].[Posting Date] AS DataRegistrazione, IIf([sales invoice line.Gen_ Bus_ Posting Group]="NAZIONALE","ITALIA","ESTERO") AS Paese, [Sales Invoice Header].[Currency Code] AS Valuta
FROM (([Sales Invoice Line] INNER JOIN [Sales Invoice Header] ON [Sales Invoice Line].[Document No_] = [Sales Invoice Header].No_) INNER JOIN Item ON [Sales Invoice Line].No_ = Item.No_) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_
WHERE ((([Sales Invoice Line].Type)=19 Or ([Sales Invoice Line].Type)=20) AND (([Sales Invoice Header].[Posting Date]) Between [forms]![principale]![datainiziale] And [forms]![principale]![datafinale]) AND ((Item.[advertising material])=0));

